 1	import type { FC } from 'react';
 2	
 3	import WizardStepContainer from '@components/common/WizardStepContainer';
 4	import { EmptyState, EmptyStateHeader, EmptyStateIcon, Spinner } from '@patternfly/react-core';
 5	import { useForkliftTranslation } from '@utils/i18n';
 6	
 7	import { planStepNames, PlanWizardStepId } from '../../constants';
 8	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
 9	
10	import GeneralInfoReviewSection from './GeneralInfoReviewSection';
11	import HooksReviewSection from './HooksReviewSection';
12	import MigrationTypeReviewSection from './MigrationTypeReviewSection';
13	import NetworkMapReviewSection from './NetworkMapReviewSection';
14	import OtherSettingsReviewSection from './OtherSettingsReviewSection';
15	import ReviewStepErrorState from './ReviewStepErrorState';
16	import StorageMapReviewSection from './StorageMapReviewSection';
17	import VirtualMachinesReviewSection from './VirtualMachinesReviewSection';
18	
19	type ReviewStepProps = {
20	  error: Error | undefined;
21	  onBackToReviewClick: () => void;
22	  isLiveMigrationFeatureEnabled: boolean;
23	};
24	
25	const ReviewStep: FC<ReviewStepProps> = ({
26	  error,
27	  isLiveMigrationFeatureEnabled,
28	  onBackToReviewClick,
29	}) => {
30	  const { t } = useForkliftTranslation();
31	  const {
32	    formState: { isSubmitting },
33	  } = useCreatePlanFormContext();
34	
35	  if (isSubmitting) {
36	    return (
37	      <EmptyState className="pf-v6-u-h-100">
38	        <EmptyStateHeader
39	          titleText={t('Creating plan')}
40	          headingLevel="h4"
41	          icon={<EmptyStateIcon icon={Spinner} />}
42	        />
43	      </EmptyState>
44	    );
45	  }
46	
47	  if (error?.message) {
48	    return <ReviewStepErrorState error={error.message} onBackToReviewClick={onBackToReviewClick} />;
49	  }
50	
51	  return (
52	    <WizardStepContainer
53	      title={planStepNames[PlanWizardStepId.ReviewAndCreate]}
54	      description={t(
55	        'Make sure your migration plan looks correct. To make any changes, click directly on the step you want to go to or press the back button.',
56	      )}
57	      testId="create-plan-review-step"
58	    >
59	      <GeneralInfoReviewSection />
60	      <VirtualMachinesReviewSection />
61	      <NetworkMapReviewSection />
62	      <StorageMapReviewSection />
63	      <MigrationTypeReviewSection isLiveMigrationFeatureEnabled={isLiveMigrationFeatureEnabled} />
64	      <OtherSettingsReviewSection isLiveMigrationFeatureEnabled={isLiveMigrationFeatureEnabled} />
65	      <HooksReviewSection />
66	    </WizardStepContainer>
67	  );
68	};
69	
70	export default ReviewStep;

